import React from 'react';
import { motion } from 'framer-motion';
import { cn } from '@/lib/utils';

export interface LinkCardProps extends React.AnchorHTMLAttributes<HTMLAnchorElement> {
  title: string;
  description: string;
  imageUrl: string;
  href?: string;
  step?: string;
  icon?: React.ReactNode;
}

const LinkCard = React.forwardRef<HTMLAnchorElement, LinkCardProps>(
  ({ className, title, description, imageUrl, href, step, icon, ...props }, ref) => {
    const cardVariants = {
      initial: { scale: 1, y: 0 },
      hover: {
        scale: 1.03,
        y: -5,
        transition: {
          type: 'spring',
          stiffness: 300,
          damping: 15,
        },
      },
    };

    return (
      <motion.a
        ref={ref}
        href={href || '#'}
        target={href ? "_blank" : undefined}
        rel={href ? "noopener noreferrer" : undefined}
        className={cn(
          'group relative flex h-80 w-full max-w-sm flex-col justify-between overflow-hidden',
          'rounded-2xl border bg-card p-6 text-card-foreground shadow-sm bg-white',
          'focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2',
          className
        )}
        variants={cardVariants}
        initial="initial"
        whileHover="hover"
        aria-label={`Link to ${title}`}
        {...props}
      >
        <div className="z-10 flex flex-col h-full">
          {step && icon && (
            <div className="flex items-start justify-between mb-6">
              <div className="text-5xl font-bold text-slate-200">{step}</div>
              <div className="w-14 h-14 bg-slate-100 rounded-xl flex items-center justify-center text-slate-700">
                {icon}
              </div>
            </div>
          )}
          <h3 className="mb-2 font-serif text-2xl font-medium tracking-tight text-slate-900">
            {title}
          </h3>
          <p className="max-w-[80%] text-sm text-slate-600">
            {description}
          </p>
        </div>

        <div className="absolute bottom-0 right-0 h-32 w-32 translate-x-1/4 translate-y-1/4 transform opacity-50 md:h-48 md:w-48 group-hover:opacity-100 transition-opacity">
          <motion.img
            src={imageUrl}
            alt={`${title} illustration`}
            className="h-full w-full object-contain transition-transform duration-300 ease-out group-hover:scale-110"
          />
        </div>
      </motion.a>
    );
  }
);

LinkCard.displayName = 'LinkCard';

export { LinkCard };
